INSERT INTO `content` (`id`, `type`, `title`, `slug`, `description`, `content`, `url`, `approval_status`, `author_id`, `editor_id`, `created_at`, `is_featured`, `excerpt`, `video_url`, `featured_image`, `category_id`) VALUES
('ed1ba542-61ed-11f1-98fa-60cf847a2597', 'podcast', 'How Do You Stay on Top of Media News?  Try Our Podcast!', 'how-do-you-stay-on-top-of-media-news-try-our-podcast', NULL, '<h3><strong>Listen to our New Media News Podcast!</strong></h3>\n<audio class=\"wp-audio-shortcode\" id=\"audio-1035-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-2-Web-020818.mp3?_=1\" /><a href=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-2-Web-020818.mp3\">http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-2-Web-020818.mp3</a></audio>\n<p><strong>This Week:</strong></p>\n<ul>\n<li>Facebook is for Friends not News!</li>\n<li>Will Mark Zuckerberg Change the Future of the News (Feed?)</li>\n<li>Muckrock&#8217;s Slack Channel for Journalists.</li>\n<li>How Has Mobile Shaped Citizen Journalism?</li>\n<li>Is Snapchat Discover News with a Millenial Twist?</li>\n<li>Did Social Media Ride to the Rescue after Hurricane Maria?</li>\n<li>Gaming Fans Vent on Reddit: Are the Game Publishers Listing?</li>\n<li>How Is Instagram Using AI?</li>\n</ul>\n<p>Global Media News is a weekly webcast covering new media news from around the world.  GMN is a production of  Media Studies students from the <a href=\"http://www.oldwestbury.edu/\" target=\"_self\">SUNY College @ Old Westbury.</a>   We scour the web for news about new media, journalism and technology.</p>\n<p>Listen to our next podcast streaming live on OWWR: Thursday February 15, 2018 @ 10 am EST.</p>\n<p>Can&#8217;t listen live? Our next podcast  will be posted by 2:00pm, Thursday February 15, 2018,  2018.</p>\n<p><a href=\"http://feeds.feedburner.com/GlobalMediaNews\" target=\"_self\">Subscribe Now!</a></p>\n', NULL, 'APPROVED', 'AM327', NULL, '2018-02-09 10:26:53', 0, 'Listen to our New Media News Podcast! This Week: Facebook is for Friends not News! Will Mark Zuckerberg Change the Future of the News (Feed?) Muckrock’s Slack Channel for Journalists. How Has Mobile Shaped Citizen Journalism? Is Snapchat Discover News with a Millenial Twist? Did Social Media Ride to the Rescue after Hurricane Maria? Gaming…\n', NULL, NULL, 1),
('ed1c064e-61ed-11f1-98fa-60cf847a2597', 'article', 'OWTV:  Join & Shine!  Every Wednesday during Common Hour!', 'owtv-join-shine-every-wednesday-during-common-hour', NULL, '<h4 style=\"text-align: center;\">Come Be Our Valentine!  This Wednesday 2/14 during Common Hour at OWTV</h4>\n<figure id=\"attachment_1040\" aria-describedby=\"caption-attachment-1040\" style=\"width: 610px\" class=\"wp-caption aligncenter\"><a href=\"https://www.youtube.com/user/OldWestburyTV/videos\"><img loading=\"lazy\" decoding=\"async\" class=\"wp-image-1040 size-large\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/owtv-Open-house-post-1024x640.jpg\" alt=\"\" width=\"610\" height=\"381\" /></a><figcaption id=\"caption-attachment-1040\" class=\"wp-caption-text\">Join OWTV this Wednesday, Common Hour in the G-Wing of Campus Center!</figcaption></figure>\n<p>Learn all elements of television &amp; video production including cameras, lighting, pre and post-production, script writing and much more!   You can report, shoot, and edit news packages and cover campus wide events.   We create live-streaming and pre-recorded programming in our newly refreshed TV Studio.</p>\n<h4 style=\"text-align: center;\">Visit us  in the G-Wing of Campus Center (G-127)</h4>\n<h4 style=\"text-align: center;\">Contact our New Station Manager:  Jing Wang  &amp; OWTV</h4>\n<h4 style=\"text-align: center;\">Tel. <a href=\"tel:516-876-2793\" target=\"_blank\" rel=\"noopener\">516-876-2793</a>  Email:  <u><a href=\"mailto:owtv@oldwestbury.edu\" target=\"_blank\" rel=\"noopener\">owtv@oldwestbury.edu</a></u>.</h4>\n<h4 style=\"text-align: center;\"><strong>Twitter:</strong> <u><a href=\"https://twitter.com/oldwesttv\">OldWestTV</a></u>  |  <strong>YouTube:</strong> <u><a href=\"https://www.youtube.com/user/OldWestburyTV/videos\">OldWestburyTV</a></u></h4>\n<p><a href=\"https://www.youtube.com/user/OldWestburyTV/videos\"><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter size-full wp-image-1042\" src=\"uploads/owtv-logo.jpg\" alt=\"\" width=\"200\" height=\"100\" /></a></p>\n', NULL, 'APPROVED', 'AM327', NULL, '2018-02-10 20:54:01', 0, 'Come Be Our Valentine!  This Wednesday 2/14 during Common Hour at OWTV Learn all elements of television & video production including cameras, lighting, pre and post-production, script writing and much more!   You can report, shoot, and edit news packages and cover campus wide events.   We create live-streaming and pre-recorded programming in our newly refreshed TV Studio. Visit…\n', NULL, NULL, 1),
('ed1cb90d-61ed-11f1-98fa-60cf847a2597', 'article', 'Follow the Money: Dolar & DelGuidice on Budget, Deficits, and Debt', 'follow-the-money-dolar-delguidice-on-budget-deficits-and-debt', NULL, '<h2 style=\"text-align: center;\">“Democracy is not a spectator sport…If you’re going to play the game properly you’d better know every rule.”</h2>\n<p style=\"text-align: center;\">&#8212; Congresswoman Barbara Jordan</p>\n<p><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter size-large wp-image-1049\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/Talk-on-the-Budget-and-Deficits-791x1024.jpg\" alt=\"\" width=\"610\" height=\"790\" /></p>\n<p style=\"text-align: center;\"><strong>&#8220;It has never been more important to know the tax and spending rules/decisions of our government and what are the forces driving and changing those rules.&#8221;   &#8212; Dr. Thomas DelGiudice &amp; Dr. Veronika Dolar, </strong></p>\n<div>\n<p><strong><a href=\"https://www.oldwestbury.edu/people/dolarv\" target=\"_blank\" rel=\"noopener\">Dolar</a> &amp; <a href=\"https://www.oldwestbury.edu/people/delgiudicet\" target=\"_blank\" rel=\"noopener\">DelGuidice</a> </strong>of the <a href=\"https://www.oldwestbury.edu/departments/politics\" target=\"_blank\" rel=\"noopener\">PEL</a> department will be hosting an &#8220;interactive discussion&#8221; about the budget, deficits and debt  on <strong>Thursday February 15th at 11:20 AM in NAB 1100</strong>.</p>\n<p><strong>Key Terms &amp; Trends:</strong> Learn about the economic trends, data and key terms you need to know to &#8220;follow the money.&#8221;   Should we worry about big budgets and bigger deficits? Who gets to decide?  According to Dolar &amp; DelGuidice,</p>\n</div>\n<blockquote>\n<div>\n<p>&#8220;our government has made the decision to double the deficit by 2019 to over <u>a trillion dollars a year and this when we are at the top of the business cycle</u>. Beyond the sheer size and the vulnerability it creates for the country to address a future crisis or the next downturn, there is the very important issue of how we collect and spend the funds and what happens to working families going forward, the vulnerable and the prospects for our students’ generation. Finally there are so many ways that not knowing makes us a victim of the many clichés that get thrown around about deficits, taxes and spending.&#8221;</p>\n</div>\n</blockquote>\n<div>\n<h2 style=\"text-align: center;\">Ask the Economists!</h2>\n<p style=\"text-align: center;\"><strong>Budgets, Deficits &amp; Debt (Oh My!) on Thursday, February 15th at 11:20 AM in NAB 1100</strong>.</p>\n</div>\n', NULL, 'APPROVED', 'AM327', NULL, '2018-02-10 22:45:28', 0, '“Democracy is not a spectator sport…If you’re going to play the game properly you’d better know every rule.” — Congresswoman Barbara Jordan “It has never been more important to know the tax and spending rules/decisions of our government and what are the forces driving and changing those rules.”   — Dr. Thomas DelGiudice & Dr. Veronika Dolar,  Dolar…\n', NULL, NULL, 1),
('ed1d19e3-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Dominate Mount St. Mary’s in 87-50 Victory', 'panthers-dominate-mount-st-marys-in-87-50-victory', NULL, '<p><span style=\"font-weight: 400;\">The Old Westbury Panthers men’s basketball team had an impressive performance on the afternoon of February 1st, defeating Mount St. Mary’s College 87-50 at home. From the very beginning, the Panthers set the tone, charging to an early lead that Mount St. Mary’s was unable to recover from.</span></p>\n<p><span style=\"font-weight: 400;\">The game tipped off with Old Westbury’s Joel Ofori winning the opening jump ball, and the Panthers wasted no time in asserting control. They quickly built a 5-0 lead, with Ofori contributing early. By the 8-minute mark of the first half, Old Westbury had a commanding 20-6 advantage. The team’s defensive pressure and offensive efficiency continued to shine throughout the first half, and by halftime, the Panthers had extended their lead to 41-18.</span></p>\n<p><span style=\"font-weight: 400;\">Mount St. Mary’s struggled offensively in the first half, shooting just 25.8% from the field and a horrid 9% from three-point range (1-of-11). In contrast, the Panthers displayed solid shooting, connecting on 45% of their field goals and 29.4% from beyond the arc.</span></p>\n<p><span style=\"font-weight: 400;\">Though the Mountaineers managed to improve their shooting in the second half finishing at 31.4% from the field and 13% from three-point range their efforts fell short as Old Westbury&#8217;s lead was too much to overcome. The Panthers closed out the game in dominant fashion, securing the 87-50 victory.</span></p>\n<p><span style=\"font-weight: 400;\">It was a well-rounded team effort from the Panthers, with four players scoring in double figures. Jamari “Florida” Williams led the charge with 16 points, 5 assists, and 6 rebounds. Kellen Leake, ranked 7th in the conference for three-point shooting, had a rare off-night from beyond the arc (2-of-11), but still managed to contribute 16 points and 3 rebounds. Amadi Lee-Kane, the Panthers&#8217; “Franchise” player, had an up-and-down shooting performance (1-of-7 from three, 3-of-10 from the field), but still posted a solid 14 points, 6 rebounds, and 3 assists.</span></p>\n<p><span style=\"font-weight: 400;\">Joel Ofori was a force in the paint, recording a double-double with 11 points and 13 rebounds. Chris Smith and Michael &#8220;Ocho&#8221; Obi were strong contributors off the bench, with Smith finishing with 7 points and 6 rebounds, and Obi adding 6 points and 6 rebounds.</span></p>\n<p><span style=\"font-weight: 400;\">Mount St. Mary’s was led by Cyran Connor, who posted 11 points and 6 rebounds. However, the rest of the team struggled to find their rhythm, with no other player scoring more than 5 points.</span></p>\n<p><span style=\"font-weight: 400;\">With this win, Old Westbury improved to 8-10 on the season and 3-7 in Skyline Conference play, moving into 4th place in their division. The victory has given the Panthers a boost as they continue to push for a spot in the conference playoffs. Looking ahead, Old Westbury will face a tough challenge in their next game against Mount St. Vincent on February 5th, who sit at 7-12 overall and 4-6 in conference play. As they look to build on this dominant performance, the Panthers will aim to climb further up the standings in their pursuit of a postseason berth.</span></p>\n', NULL, 'APPROVED', 'AP963', NULL, '2025-03-02 17:53:10', 0, 'The Old Westbury Panthers men’s basketball team had an impressive performance on the afternoon of February 1st, defeating Mount St. Mary’s College 87-50 at home. From the very beginning, the Panthers set the tone, charging to an early lead that Mount St. Mary’s was unable to recover from. The game tipped off with Old Westbury’s…\n', NULL, NULL, 3),
('ed1d7e2c-61ed-11f1-98fa-60cf847a2597', 'article', 'Inside the NCAA: My Experience at the Student Immersion Program', 'inside-the-ncaa-my-experience-at-the-student-immersion-program', NULL, '<p><span style=\"font-weight: 400;\">The NCAA annually hosts the Student Immersion Program, inviting 40 minority students from Division III institutions across the country to explore careers in coaching, athletics administration, and NCAA governance. The goal of this program is to increase diversity within intercollegiate athletics leadership, exposing student-athletes to opportunities they may have never considered before. </span></p>\n<p><span style=\"font-weight: 400;\">This year, I had the privilege of attending the NCAA 2025 Convention in Nashville, Tennessee from January 14-17. Going into the experience, I wasn’t entirely sure what to expect, but from the moment I arrived, I was surrounded by an incredible cohort of student-athletes, dedicated mentors, and top professionals in collegiate athletics. Every conversation, panel, and session reinforced why I am so passionate about the future of athletics and why I want to be part of shaping that future. </span></p>\n<p><span style=\"font-weight: 400;\">Throughout the program, we attended sessions designed to educate, inspire, and prepare us for careers in sports. Workshops like the DISC Leadership Assessment, Maximizing Your Resources, and DEIB (Diversity, Equity, Inclusion, and Belonging) in Athletics provided us with real world insights and tools to grow as future leaders. These sessions weren’t just about learning the technical aspects of the industry, they challenged us to think about the impact we want to make in athletics and how we can use our voices to bring change.</span></p>\n<p><span style=\"font-weight: 400;\">A standout moment for me was attending the Women of the Year Awards, a ceremony honoring outstanding female student-athletes for their achievements in academics, athletics, leadership, and service. As a woman in sports, seeing these incredible women being recognized for their hard work and dedication was incredibly inspiring. It reinforced my belief in the importance of representation and the impact women can have in shaping the future of athletics.</span></p>\n<p><span style=\"font-weight: 400;\">One of the biggest takeaways was realizing just how impactful Division III athletics really is. Often, as DIII athletes, it feels like we don’t get the same level of recognition as other divisions. However, being in that space surrounded by leaders who are deeply invested in advocating for the DIII student-athlete experience was empowering. It reminded me that Division III athletics is just as meaningful, offering unique opportunities for both personal and professional growth. I also gained a new appreciation for the behind-the-scenes work that goes into advocating for student-athletes. We tend to focus so much on our sport, practices, games, training that we don’t always recognize the countless decisions being made at the administrative level that directly affect our experiences. The program gave me a clearer understanding of how policies are developed, how decisions are made, and how leaders in intercollegiate athletics fight to enhance the student-athlete experience every single day. </span></p>\n<p><span style=\"font-weight: 400;\">Attending the NCAA Student Immersion Program was a truly eye-opening experience. Not only did I explore potential career paths in coaching and administration, but I also gained a deeper appreciation for the dedication and effort that goes into shaping collegiate athletics. This experience reinforced my commitment to supporting student-athletes and ensuring that their voices are heard. I left feeling more inspired than ever to take on a meaningful role in the future of sports.</span></p>\n<figure id=\"attachment_11186\" aria-describedby=\"caption-attachment-11186\" style=\"width: 450px\" class=\"wp-caption alignnone\"><img loading=\"lazy\" decoding=\"async\" class=\"size-medium wp-image-11186\" src=\"uploads/ImmersionProgram-450x600.jpg\" alt=\"\" width=\"450\" height=\"600\" srcset=\"uploads/ImmersionProgram-450x600.jpg 450w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/ImmersionProgram-900x1200.jpg 900w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/ImmersionProgram-768x1024.jpg 768w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/ImmersionProgram-1152x1536.jpg 1152w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/ImmersionProgram-225x300.jpg 225w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/ImmersionProgram.jpg 1200w\" sizes=\"auto, (max-width: 450px) 100vw, 450px\" /><figcaption id=\"caption-attachment-11186\" class=\"wp-caption-text\">Division III Student Immersion Program</figcaption></figure>\n<figure id=\"attachment_11183\" aria-describedby=\"caption-attachment-11183\" style=\"width: 450px\" class=\"wp-caption alignnone\"><img loading=\"lazy\" decoding=\"async\" class=\"size-medium wp-image-11183\" src=\"uploads/JulianaNCAAStudentImmersion-450x600.png\" alt=\"\" width=\"450\" height=\"600\" srcset=\"uploads/JulianaNCAAStudentImmersion-450x600.png 450w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/JulianaNCAAStudentImmersion-900x1200.png 900w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/JulianaNCAAStudentImmersion-768x1024.png 768w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/JulianaNCAAStudentImmersion-1152x1536.png 1152w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/JulianaNCAAStudentImmersion-225x300.png 225w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/JulianaNCAAStudentImmersion.png 1200w\" sizes=\"auto, (max-width: 450px) 100vw, 450px\" /><figcaption id=\"caption-attachment-11183\" class=\"wp-caption-text\">Juliana Vasquez on Day 2 of the NCAA Convention (Juliana Vasquez)</figcaption></figure>\n<p><span style=\"font-weight: 400;\">For any student-athlete looking to make an impact beyond competition, I highly recommend exploring opportunities like this. It’s more than just a networking event, it&#8217;s a chance to learn, grow, and be part of the ongoing evolution of collegiate athletics.</span></p>\n', NULL, 'APPROVED', 'JV375', NULL, '2025-03-02 21:00:32', 0, 'The NCAA annually hosts the Student Immersion Program, inviting 40 minority students from Division III institutions across the country to explore careers in coaching, athletics administration, and NCAA governance. The goal of this program is to increase diversity within intercollegiate athletics leadership, exposing student-athletes to opportunities they may have never considered before.  This year, I…\n', NULL, NULL, 6),
('ed1ded5b-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Secure Senior Night Win', 'panthers-secure-senior-night-win', NULL, '<p><span style=\"font-weight: 400;\">The Old Westbury Panthers delivered an exhilarating victory on Senior Night, securing a hard-fought 71-68 win over St. Joseph’s University Brooklyn on February 15th. Before the game started there were tributes to seniors Michael “Ocho” Obi, Amadi Lee-Kane, and the team manager Cameron Harewood. </span></p>\n<p><span style=\"font-weight: 400;\">The game started with high energy, as the Panthers quickly grabbed the lead. Joel Ofori won the opening jump ball, and Amadi Lee-Kane followed with a smooth floater to put Old Westbury on the scoreboard. By the 6-minute mark, the Panthers were up 13-4, displaying their dominance on both ends of the court. However, St. Joseph&#8217;s didn’t back down and with 8 minutes to go in the first half the score was 26-22. The Panthers had a late surge that extended their lead to 43-34 at the end of the half.</span></p>\n<p><span style=\"font-weight: 400;\">At halftime, Old Westbury’s offense was firing on all cylinders. Freshman Zion Williams led the charge with 14 points, 2 rebounds, and 4 assists, shooting 5-9 from the field. Jamari Williams (#0) chipped in 10 points, 5 rebounds, 3 assists, and 2 steals, while Kellen Leake contributed 11 points, going 3-4 from beyond the arc. Old Westbury’s shooting was impressive, hitting 53.1% of their field goals (17-32) and 45.5% from three-point range (5-11).</span></p>\n<p><span style=\"font-weight: 400;\">Brooklyn had a balanced attack, with Collin Mills leading the charge with 9 points. Chris Williams (9 points, 4 rebounds, 2 assists) and Jaylen Gordon (6 points, 3 rebounds) kept the game within reach.</span></p>\n<p><span style=\"font-weight: 400;\">Brooklyn came out the break on fire starting with a 15-5 run to tie the game at 49-49. With 14 minutes left, the Panthers faced the pressure of needing a victory to keep their playoff hopes alive. Despite regaining some rhythm, Old Westbury found themselves down 58-59 with 10 minutes to go.</span></p>\n<p><span style=\"font-weight: 400;\">As the clock ticked down, the game’s intensity rose. Kellen Leake’s clutch free throws put the Panthers back on top at 65-63 with 6 minutes remaining. With Brooklyn still within striking distance, Amadi Lee-Kane delivered two critical free throws to push the lead to 71-68 with 30 seconds left. Brooklyn had one last chance to force overtime but was unable to hit a contested three-pointer with 5 seconds on the clock, thanks to stellar defense from Old Westbury.</span></p>\n<p><span style=\"font-weight: 400;\">The Panthers have now won two straight games, building momentum as they head into the final stretch of the regular season. Their next challenge will be against their rivals, Farmingdale, in a must-win game at home on Wednesday February 19</span><span style=\"font-weight: 400;\">th</span><span style=\"font-weight: 400;\"> at 5 PM. With only two games left, the Panthers are determined to finish strong and secure a playoff berth.</span><img loading=\"lazy\" decoding=\"async\" class=\"alignnone wp-image-11203 size-medium\" src=\"uploads/SeniorNightWin-e1741879680655-600x408.png\" alt=\"Men\'s bastketball preparing to play for the Senior Night game\" width=\"600\" height=\"408\" srcset=\"uploads/SeniorNightWin-e1741879680655-600x408.png 600w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/SeniorNightWin-e1741879680655-300x204.png 300w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/SeniorNightWin-e1741879680655.png 736w\" sizes=\"auto, (max-width: 600px) 100vw, 600px\" /></p>\n<p>Photo Credit: Old Westbury Athletic Communications</p>\n', NULL, 'APPROVED', 'AP963', NULL, '2025-03-27 11:55:53', 0, 'The Old Westbury Panthers delivered an exhilarating victory on Senior Night, securing a hard-fought 71-68 win over St. Joseph’s University Brooklyn on February 15th. Before the game started there were tributes to seniors Michael “Ocho” Obi, Amadi Lee-Kane, and the team manager Cameron Harewood.  The game started with high energy, as the Panthers quickly grabbed…\n', NULL, NULL, 7),
('ed1e5c63-61ed-11f1-98fa-60cf847a2597', 'article', 'Black Student Union Hosts “A Night in Hollywood” Met Gala', 'black-student-union-hosts-a-night-in-hollywood-met-gala', NULL, '<p><span style=\"font-weight: 400;\">On Thursday February 13th, the Black Student Union hosted “A Night in Hollywood” Met Gala for the student body, an evening of unity, fashion, and fun during the heart of Black History Month. Dressed for the occasion, both under and upperclassmen were able to come together and celebrate black excellence, taking pride in each other as well as the achievements made throughout the community.</span></p>\n<figure id=\"attachment_11208\" aria-describedby=\"caption-attachment-11208\" style=\"width: 600px\" class=\"wp-caption alignnone\"><img loading=\"lazy\" decoding=\"async\" class=\"size-medium wp-image-11208\" src=\"uploads/BSUSign-600x400.png\" alt=\"\" width=\"600\" height=\"400\" srcset=\"uploads/BSUSign-600x400.png 600w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/BSUSign-1200x800.png 1200w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/BSUSign-768x512.png 768w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/BSUSign-1536x1023.png 1536w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/BSUSign-300x200.png 300w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/BSUSign.png 1600w\" sizes=\"auto, (max-width: 600px) 100vw, 600px\" /><figcaption id=\"caption-attachment-11208\" class=\"wp-caption-text\">Black Student Union holds &#8220;A Night in Hollywood Gala&#8221; (Sam Hamilton)</figcaption></figure>\n<p><span style=\"font-weight: 400;\">The Student Union Multipurpose Room looked a lot different, decorated in a multitude of stars over black, red, and gold drapery. Attendees could take photos in front of the cinema-esque BSU sign on the red carpet, or go for a 360 panoramic video with friends. The real festivities began with a heartfelt poem by BSU President Kayla Simone Wilson. An ode to the importance of black history, Kayla delivered a powerful message on how black accomplishments are woven into the seams of our nation, unable to be stifled, and a reminder to continue being unapologetically proud of our roots. Following Kayla’s speech was a fashion walk by Glamazon, showing off the variety of elegant outfits worn to match the gala theme. Food was served shortly after, with no shortage of good music once the dance floor was opened. I took this opportunity to interview several attendees.</span></p>\n<p><span style=\"font-weight: 400;\">“We contribute so much to society,” said Elijah Black, a senior and Biology major, when I asked what black history means to him. “Whether it be culture…math….music, literature, you know, Langston Hughes [and] Octavia Butler…STEM…we wouldn’t be [in] space without Katherine [Johnson]. Black history is recognizing what black people have done for the planet.” Jara Gonzalez, a Psychology major, shared similar thoughts. “Black history, of course, is American history. But it’s not just centered [on] Black History Month. It’s the whole year, the whole decade, and everything, honestly.”</span></p>\n<p><span style=\"font-weight: 400;\">The gala was one of many Black History Month events planned for February. It stands as a beacon of empowerment as Donald Trump’s second presidential term has brought on a slew of executive orders. The rders have undermined Diversity, Equity, and Inclusion initiatives in government positions and federally funded programs. Elijah Black, upon me asking if this function had additional impact because of current events, continued: “[…] Events like this, especially now with the rise of fascism and white supremacy…more black hosted events like this are really important in this climate.”</span></p>\n<p><span style=\"font-weight: 400;\">At the end of the night, as the music started to wind down and people took their leave into the cold, I got to talk with Kayla Simone Wilson about her thoughts on black history and her successful gala. “Black history means struggle, prevalence, success, pain. It’s everything in between. I think [this gala] means a lot. We’re giving a, for lack of better terms, a big F you to things trying to keep us down. This is showing people…we know what’s right. We know that DEI is what keeps us interesting, it keeps us together, connected. So it’s things like this that need to keep [happening].”</span></p>\n<p><span style=\"font-weight: 400;\">The BSU did a fantastic job at boosting morale in a time where it is few and far between. “We’re here. Come join [the BSU], come see us,” Kayla encouraged fellow Old Westbury students as we concluded our interview. “Everybody’s welcome, every walk of life. Whoever wants to learn, share, laugh, love, we’re here for you.” </span></p>\n<p>&nbsp;</p>\n', NULL, 'APPROVED', 'SH903', NULL, '2025-03-19 14:08:53', 0, 'On Thursday February 13th, the Black Student Union hosted “A Night in Hollywood” Met Gala for the student body, an evening of unity, fashion, and fun during the heart of Black History Month. Dressed for the occasion, both under and upperclassmen were able to come together and celebrate black excellence, taking pride in each other…\n', NULL, NULL, 1),
('ed1ea8f5-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Fall Short to Mount Saint Vincent in a Hard-Fought Conference Matchup', 'panthers-fall-short-to-mount-saint-vincent-in-a-hard-fought-conference-matchup', NULL, '<p><span style=\"font-weight: 400;\">The Old Westbury Panthers faced a tough road test on the night of February 5th, as they traveled to Mount Saint Vincent for a 6:00 PM men’s basketball conference game. The Panthers, who entered the game with a conference victory against Mount Saint Mary’s, were looking to keep the momentum going against the Dolphins, but after a competitive contest, they ultimately fell short, losing 82-76. Despite their efforts, Old Westbury’s turnovers and missed opportunities in the closing minutes allowed Mount Saint Vincent to secure the victory.</span></p>\n<p><span style=\"font-weight: 400;\">A competitive start, but the Panthers struggled to maintain momentum. The game began with Joel Ofori winning the tip-off for Old Westbury. Chris Smith quickly made his mark by hitting the first basket of the game from deep 3-point range, giving the Panthers an early lead. However, the Dolphins quickly answered, and both teams went back and forth for much of the first half. At the 7-minute mark, the game was tied at 12-12, as both teams displayed solid shooting performances.</span></p>\n<p><span style=\"font-weight: 400;\">Old Westbury struggled to keep pace towards the end half of the first period, as Mount Saint Vincent pulled ahead. With just under 3 minutes remaining in the half, the Dolphins had extended their lead to 41-31, with Old Westbury trailing by 10 points. Despite a late surge from the Panthers, the half ended with Mount Saint Vincent holding a 46-37 lead.</span></p>\n<p><span style=\"font-weight: 400;\">Several Panthers had solid individual performances in the first half. Joel led the team with 7 points on 3-of-5 shooting. Amadi Lee Kane also contributed 6 points, going 3-of-6 from the field. Zion Williams had 6 points as well, shooting 2-of-5, including a strong 2-of-3 performance from behind the arc.  Despite solid shooting percentages Old Westbury hitting 45.7% from the field and Mount Saint Vincent shooting 45% the Panthers were undone by their turnovers. Old Westbury committed 9 turnovers in the first half compared to just 3 for the Dolphins, and Vincent capitalized by scoring 8 points off those turnovers, while Old Westbury only managed 2.</span></p>\n<p><span style=\"font-weight: 400;\">The second half began with a quick burst from Old Westbury. Jamari started the half with 2 made free throws, followed by a defensive rebound and an assist to Joel, which made it 41-46. The Panthers came out with renewed energy, going on an 8-3 run to close the gap to 51-48. Zion was instrumental in this stretch, recording back-to-back assists one to Amadi and the other to Kellen Leakes, who found his shooting rhythm in the second half, starting 2-of-3. With just over 10 minutes left in the game, the Panthers had fought their way back and briefly took the lead, 62-61, after a well-timed assist from Zion to Michael Obi. </span></p>\n<p><span style=\"font-weight: 400;\">However, the lead was short-lived, as Mount Saint Vincent regained the advantage with 5:43 remaining in the game. In the final stretch, Old Westbury’s inability to protect the ball and execute under pressure hurt them. Costly turnovers allowed the Dolphins to pull away, and despite a valiant effort, the Panthers were unable to recover. The game ended with a final score of 82-76 in favor of Mount Saint Vincent.</span></p>\n<p><span style=\"font-weight: 400;\">Despite the loss, several players had standout performances for the Panthers. Michael Obi had an impressive 11 points and 2 rebounds on 5-of-8 shooting, including 1-of-1 from 3-point range off the bench. Joel contributed another double-double with 12 points and 10 rebounds, shooting 5-of-9 from the field. Zion also finished with a double-double, tallying 10 points and 12 assists while shooting 3-of-10 from the field and 2-of-4 from 3-point range. Kellen added 18 points, despite his struggles in the first half, and shot 4-of-11 from beyond the arc. Jamari and Amadi struggled to make their usual impact, as Jamari finished with 9 points on 3-of-8 shooting, while Amadi scored 9 points on 4-of-8 shooting and had 6 rebounds,7 assists.</span></p>\n<p><span style=\"font-weight: 400;\">The game saw 8 ties and 7 lead changes. However, the turnovers were a significant issue for Old Westbury throughout the game. In the second half, Old Westbury shot 46.7% from the field and 44.7% from 3-point range, while Mount Saint Vincent shot just 36.4% from the field and 21.3% from behind the arc. Despite these statistical advantages, Old Westbury’s 17 turnovers compared to 6 for Mount Saint Vincent proved costly. Another key factor in the game was Mount Saint Vincent’s strong bench play, as they outscored Old Westbury’s bench 36-23. The Panthers will need to improve their bench production moving forward to remain competitive in conference play.</span></p>\n<p><span style=\"font-weight: 400;\">The Panthers showed resilience in their comeback attempt, but Mount Saint Vincent’s ability to capitalize on mistakes and maintain control late in the game secured them the win. Looking ahead, Old Westbury will need to focus on limiting turnovers and improving their execution in high-pressure situations to secure future victories in conference play. Next up for the Panthers is another tough conference away game against Saint Joseph’s University Long Island who are 7-4 in conference play, on February 8th.</span></p>\n', NULL, 'APPROVED', 'AP963', NULL, '2025-03-19 14:20:24', 0, 'The Old Westbury Panthers faced a tough road test on the night of February 5th, as they traveled to Mount Saint Vincent for a 6:00 PM men’s basketball conference game. The Panthers, who entered the game with a conference victory against Mount Saint Mary’s, were looking to keep the momentum going against the Dolphins, but…\n', NULL, NULL, 3),
('ed1f1294-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Aim High After Historic 2024 Run', 'panthers-aim-high-after-historic-2024-run', NULL, '<p><span style=\"font-weight: 400;\">As the 2025 season begins, the Panthers look to build on a historic 2024 run that saw them finish 24-14 and reach the Skyline Conference Championship for the first time. With a 13-8 conference record, they stunned top-seeded opponents in a resilient postseason push. Now, fueled by momentum and high expectations, they’re ready for another shot at glory. </span></p>\n<p><span style=\"font-weight: 400;\">The Panthers have a veteran-heavy roster led by eight seniors, including myself. With only two freshmen, experience is a key strength. A graduate student adds leadership, while five new players bring extra versatility, giving the team a solid foundation.</span></p>\n<p><span style=\"font-weight: 400;\">Among the senior standouts is ace pitcher Layla Ramos, who made 20 appearances last season, recording a 2.04 ERA with 57 strikeouts. She is set to start the season alongside three former teammates from her previous institution, a connection she believes will boost the team’s chemistry. &#8220;I&#8217;m excited for the opportunity to pitch alongside my teammates one last time,&#8221; Ramos said. &#8220;The chemistry we&#8217;ve built over the years will be a huge asset to the depth Panthers softball has developed. I trust my teammates completely and can&#8217;t wait to see how far we go this season.&#8221; </span></p>\n<p><span style=\"font-weight: 400;\">The Panthers return key offensive leaders, including Senior designated hitter Madison Danin, who dominated at the plate last season with a .445 batting average and 49 hits. Her consistency and power make her a crucial part of the lineup. &#8220;Last year showed us what we’re capable of, and now that’s the standard,&#8221; Danin said. &#8220;We have the talent and drive to take that next step and win a championship.&#8221;</span></p>\n<p><span style=\"font-weight: 400;\">Senior Alaina Reilly, who posted an impressive .475 batting average and 48 hits last season, is eager to make her final year with the Panthers one to remember. With an experienced roster, she believes this team has a rare chemistry. &#8220;This group is special, and there won’t be another like it for years. We’ve played together for a long time, and that connection gives us an edge,&#8221; Reilly said. She has also witnessed the program’s growth firsthand. &#8220;We went from not having fields and barely making playoffs to being conference runner-ups. That wasn’t enough, we’re ready to take the championship.&#8221; </span></p>\n<p><span style=\"font-weight: 400;\">Head Coach Tom Pennino, who has led the program since 2020, has high expectations for this experienced Panthers team. &#8220;Strong leadership and experience make a huge difference. We have a solid group of veteran players who set the tone, and that gives us an edge,&#8221; Pennino said. &#8220;With this team’s talent and maturity, I fully expect us to be at the top of our conference.&#8221; </span></p>\n<p><span style=\"font-weight: 400;\">The Panthers were set to open their season against York College on March 8th, but the game was canceled. Their official start will now come in Clermont, Florida, from March 16-22, where they will face tough competition and build team chemistry. This trip provides a key opportunity to set the tone for the season ahead. They’ll return home ready to compete, kicking off their conference schedule on April 3rd against Baruch College. </span></p>\n<p><span style=\"font-weight: 400;\">Redemption is at the heart of the Panthers’ 2025 season. With 10 student-athletes playing their final year, the team is determined to make a statement and finish what they started. After falling just short last year, the Panthers are more motivated than ever to claim the championship and carve their names in program history.</span></p>\n<p><span style=\"font-weight: 400;\">Don’t miss the chance to support the OW Panthers as they chase greatness once again, come out and be part of history in the making!</span></p>\n', NULL, 'APPROVED', 'JV375', NULL, '2025-03-25 11:39:16', 0, 'As the 2025 season begins, the Panthers look to build on a historic 2024 run that saw them finish 24-14 and reach the Skyline Conference Championship for the first time. With a 13-8 conference record, they stunned top-seeded opponents in a resilient postseason push. Now, fueled by momentum and high expectations, they’re ready for another…\n', NULL, NULL, 8),
('ed1f5ec3-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Men’s Volleyball Team Falls Flat Against Conference Team', 'panthers-mens-volleyball-team-falls-flat-against-conference-team', NULL, '<p><span style=\"font-weight: 400;\">The Old Westbury panthers played hard in their March 7th game against the Ramapo College Roadrunners but ultimately, that wasn&#8217;t enough. The Panthers lost this match 3-0, unable to pass the 20 point threshold in a single set. </span></p>\n<p><span style=\"font-weight: 400;\">As the Panthers fall to 4-9 in the season and only have a few remaining games, their future is looking gloomy. With their playoff window closing quickly it doesn&#8217;t look likely that the Panthers will make it to the postseason but freshman Torrence Fredericks still has faith in his team. Fredericks who led his team in Kills (7) and Blocks (3) in the game against the Roadrunners still has high hopes for his team saying “If we win these next couple of games I think we can make the playoffs and we can go on a good run. All we can do is play hard and play our best”. The Panthers were unable to win a single set in this match. Players will have to reflect on themselves, as well as their teammates, to see how they can improve on all ends. Fredericks felt there were certain areas in which they fell short, stating they failed mainly in “Serve receive, I think we stepped it up after the second set. Also our defense could&#8217;ve been better [while] our offense was kinda okay”. Since Fredericks knows what to work on he’ll see if his team truly made improvements as the Panthers are set to face the Roadrunner again in a rematch on March 22nd. </span></p>\n<p><span style=\"font-weight: 400;\">When asked what he feels he can exploit in the next game after witnessing the Roadrunners in this match, Fredericks stated,  “They make mistakes just like us and I think if we keep up with our defense [we’ll be fine]. I think honestly if we work on blocking it will make a big difference in our next game with them”. After losing in such a one-sided game, many eyes will be on the Panthers in their upcoming matches to see how much have they truly improved. </span></p>\n<p>&nbsp;</p>\n', NULL, 'APPROVED', 'MD547', NULL, '2025-03-27 11:30:10', 0, 'The Old Westbury panthers played hard in their March 7th game against the Ramapo College Roadrunners but ultimately, that wasn’t enough. The Panthers lost this match 3-0, unable to pass the 20 point threshold in a single set.  As the Panthers fall to 4-9 in the season and only have a few remaining games, their…\n', NULL, NULL, 3),
('ed1fbdce-61ed-11f1-98fa-60cf847a2597', 'article', 'WGSS Center Celebrates Audre Lorde’s Birthday', 'wgss-center-celebrates-audre-lordes-birthday', NULL, '<p><span style=\"font-weight: 400;\">On Tuesday, February 18th, the SUNY Old Westbury Women’s, Gender, and Sexuality Studies (WGSS) Center held a birthday celebration for the late Audre Lorde on what would’ve been her 91st birthday. Lorde, who described herself as a &#8220;Black, lesbian, feminist, socialist, mother, warrior, poet,” was born in 1934 in Harlem to Caribbean immigrant parents. During her life, she published multiple works of poetry and feminist theory from an intersectional perspective. She was also a social justice activist who worked to make the world a more just and liberatory place.</span></p>\n<p><span style=\"font-weight: 400;\">Lorde’s powerful words have become part of the cultural language of racial and gender justice. Her quotes, “The master’s tools will never dismantle the master’s house,” “Revolution is not a one-time event,” and “Your silence will not protect you.” appear on protest signs and posters throughout the world, not always with attribution. The WGSS Center celebration was a chance to get to know the woman behind the words.</span></p>\n<p><span style=\"font-weight: 400;\">While WGSS Center volunteer Alyssandra Membreno shared a presentation with some details about Lorde’s life and her path to poetry and intersectional activism, guests enjoyed unicorn mini-cupcakes, chosen in honor of her book of poetry titled </span><i><span style=\"font-weight: 400;\">The Black Unicorn</span></i><span style=\"font-weight: 400;\">.</span></p>\n<p><span style=\"font-weight: 400;\">After the presentation, guests took turns reading from the books and printouts of Lorde’s words provided by the WGSS Center adviser, Dr. Jill Crocker. One reader quoted her famous passage on self-care from </span><i><span style=\"font-weight: 400;\">A Burst of Light</span></i><span style=\"font-weight: 400;\">, her chronicle of living with terminal liver cancer and her experiences with a racist and sexist medical system, “Caring for myself is not self-indulgence. It is self-preservation, and that is an act of political warfare.”</span></p>\n<figure id=\"attachment_11225\" aria-describedby=\"caption-attachment-11225\" style=\"width: 450px\" class=\"wp-caption alignright\"><img loading=\"lazy\" decoding=\"async\" class=\"size-medium wp-image-11225\" src=\"uploads/AudreLordeEvent-450x600.jpg\" alt=\"\" width=\"450\" height=\"600\" srcset=\"uploads/AudreLordeEvent-450x600.jpg 450w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeEvent-900x1200.jpg 900w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeEvent-768x1024.jpg 768w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeEvent-1152x1536.jpg 1152w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeEvent-225x300.jpg 225w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeEvent.jpg 1200w\" sizes=\"auto, (max-width: 450px) 100vw, 450px\" /><figcaption id=\"caption-attachment-11225\" class=\"wp-caption-text\">Students gathered at the Audre Lorde presentation in the WGSS Center (Diana Colavita)</figcaption></figure>\n<figure id=\"attachment_11226\" aria-describedby=\"caption-attachment-11226\" style=\"width: 450px\" class=\"wp-caption alignleft\"><img loading=\"lazy\" decoding=\"async\" class=\"wp-image-11226 size-medium\" src=\"uploads/AudreLordeScreen-450x600.jpg\" alt=\"Image of the Audre Lorde PowerPoint titled &quot;Audre Lorde: Black, Lesbian, Mother, Warrior, Poet&quot;\" width=\"450\" height=\"600\" srcset=\"uploads/AudreLordeScreen-450x600.jpg 450w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeScreen-900x1200.jpg 900w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeScreen-768x1024.jpg 768w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeScreen-1152x1536.jpg 1152w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeScreen-225x300.jpg 225w, https://oldwestburycatalyst.org/wp-content/uploads/2025/03/AudreLordeScreen.jpg 1200w\" sizes=\"auto, (max-width: 450px) 100vw, 450px\" /><figcaption id=\"caption-attachment-11226\" class=\"wp-caption-text\">Powerpoint by Aly Membreno</figcaption></figure>\n<p><span style=\"font-weight: 400;\">Another reader shared passages from an open letter Lorde wrote to a white feminist academic, Mary Daly, addressing Daly’s racism and erasure of the work of Black feminist academics. These were just two of the many examples of Lorde’s unflinching ability to confront bigotry and oppression head-on.</span></p>\n<p><span style=\"font-weight: 400;\">Then, the guests were invited to collage birthday cards for Audre Lorde, using images of her, as well as her own words and other craft material. People were encouraged to “get creative” with their cards, and many of the finished products showed that they did just that.</span></p>\n<p><span style=\"font-weight: 400;\">WGSS Center intern Ari Arquer, a senior majoring in sociology and minoring in social work, said that while she had read some of Lorde’s quotes before, but she “really learned who [Lorde was] and where she came from and what she stood for” at the event. When asked if she would follow through on Dr. Crocker’s directive to read more Audre Lorde on their own, she answered that she would, especially because Lorde’s family was from the same home country, Grenada, as Arquer and there isn’t a lot of West Indian representation among writers.</span></p>\n<p><span style=\"font-weight: 400;\">A quote that stood out to Arquer was “When we speak, we are afraid our words will not be heard nor welcomed, but when we are silent, we are still afraid, so it is better to speak.” Arquer appreciated that Lorde’s feminism addressed the “structural inequalities in our institutions” and felt that SUNY Old Westbury should do more programming honoring people who made an impact with their work, especially during Black History Month.</span></p>\n<p><span style=\"font-weight: 400;\">This birthday celebration was a fun, low-stress way to learn about an important figure in multiple movements to end oppression, focusing on her own words and experiences to get to know her as more than just quotes on whiteboards and stickers. As Audre Lorde herself said, “This is how I learned that if I didn’t define myself for myself, I would be crunched into other people’s fantasies for me and eaten alive.”</span></p>\n', NULL, 'APPROVED', 'DC722', NULL, '2025-03-27 11:53:38', 0, 'On Tuesday, February 18th, the SUNY Old Westbury Women’s, Gender, and Sexuality Studies (WGSS) Center held a birthday celebration for the late Audre Lorde on what would’ve been her 91st birthday. Lorde, who described herself as a “Black, lesbian, feminist, socialist, mother, warrior, poet,” was born in 1934 in Harlem to Caribbean immigrant parents. During…\n', NULL, NULL, 1);
INSERT INTO `content` (`id`, `type`, `title`, `slug`, `description`, `content`, `url`, `approval_status`, `author_id`, `editor_id`, `created_at`, `is_featured`, `excerpt`, `video_url`, `featured_image`, `category_id`) VALUES
('ed2020ab-61ed-11f1-98fa-60cf847a2597', 'article', 'A Day of Commerce: CSLI Hosts Expo for Black-Owned Businesses', 'a-day-of-commerce-csli-hosts-expo-for-black-owned-businesses', NULL, '<p><span style=\"font-weight: 400;\">Last month, SUNY Old Westbury’s entrepreneurial population had a chance to market their wares on Thursday, February 20th at the Power of Black Business Expo, another community strengthening event in honor of Black History Month. Hosted by the Center for Student Leadership &amp; Involvement, Black-owned businesses were encouraged to use the opportunity to gain traction for their endeavors during common hour in the Campus Center Atrium. Students perused tables of various shops and services, ranging from clothing and jewelry to hair and nails. Two tables were able to give a brief overview of their merchandise and the experience hosting a pop-up shop on campus.</span></p>\n<p><span style=\"font-weight: 400;\">The Finest Touch (@thefinesttouch_ on Instagram) provides wig making, wig installations, closures, sew-ins and hair styling services in Brooklyn and Long Island, owned by Shylene Labardy, a freshman and Business Administration major, and Modesty Baugh, a freshman and Public Health major. Shylene mentions that the expo has been extremely helpful to the business, saying: “It brought me a lot of exposure, I definitely got a lot of followers on my Instagram, so it really helped me a lot.” The Final Touch lists their prices on the aforementioned Instagram, with methods of getting in touch for bookings.</span></p>\n<p><span style=\"font-weight: 400;\">Saint Inertia (@st.inertia on Instagram) is another business that benefited from the event, owned by Nutifafa Colly, a junior majoring in Management Information Systems. His streetwear-based clothing line, he says, “takes inspo from my surroundings, what I like, my culture…just [things that are</span><span style=\"font-weight: 400;\">] interesting.” He explains that the nature of the business expo has given him additional opportunities that wouldn’t have been accessible with his regular marketing as the Atrium became a hub for commerce this afternoon. The Saint Inertia Instagram boasts the eclectic designs of the shop, allowing a look into the artistic vision of its creator.</span></p>\n<p><span style=\"font-weight: 400;\">According to the </span><a href=\"https://www.pewresearch.org/short-reads/2025/02/12/a-look-at-black-owned-businesses-in-the-us/\"><span style=\"font-weight: 400;\">Pew Research Center</span></a><span style=\"font-weight: 400;\"> data from 2022, Black-owned businesses only comprise an estimated 3% of all registered businesses in the US. It is for this reason that putting a spotlight on these businesses and spending locally is an integral way of building community, an attribute that we strive to cultivate as a school both on and off campus.‌</span></p>\n', NULL, 'APPROVED', 'SH903', NULL, '2025-03-27 12:05:26', 0, 'Last month, SUNY Old Westbury’s entrepreneurial population had a chance to market their wares on Thursday, February 20th at the Power of Black Business Expo, another community strengthening event in honor of Black History Month. Hosted by the Center for Student Leadership & Involvement, Black-owned businesses were encouraged to use the opportunity to gain traction…\n', NULL, NULL, 6),
('ed206d0b-61ed-11f1-98fa-60cf847a2597', 'article', 'Men’s Volleyball Struggles to Find Momentum in Season Start', 'mens-volleyball-struggles-to-find-momentum-in-season-start', NULL, '<p><span style=\"font-weight: 400;\">The SUNY Old Westbury Men’s Volleyball team was off to a rough start this season, dropping their first five games and sitting at 0-5 as of March 3rd. Despite their struggles, standout performances from key players suggest that brighter days may be ahead.</span></p>\n<p><span style=\"font-weight: 400;\">The Panthers began their season with a scrimmage against Nassau Community College, where they fell in straight sets. Hoping to bounce back, they returned home for their next four matches but have yet to secure their first win. Their most competitive game came on February 13th against Pratt Institute, a match that showcased both their resilience and areas for improvement.</span></p>\n<p><span style=\"font-weight: 400;\">From the opening set, the battle against Pratt was intense. Tied at 12-12 early on, both teams traded points in a back-and-forth contest. As the first set reached a crucial 25-25 tie, consecutive attacking errors cost the Panthers the set. Pratt carried that momentum into the second, pulling away late to take it 25-20. The third set followed a similar pattern, with Old Westbury keeping it close but ultimately falling 25-23.</span></p>\n<p><span style=\"font-weight: 400;\">With their backs against the wall, the Panthers responded in the fourth set. Led by freshman Liam Eisel’s four kills, the team went on a dominant 16-6 run to take the set 25-16 and force a decisive fifth set. However, Pratt regrouped and closed out the match with a 15-11 victory, handing Old Westbury another tough loss.</span></p>\n<p><span style=\"font-weight: 400;\">Eisel has been a bright spot for the Panthers, starting in four games and racking up an impressive 49 kills to open the season. Meanwhile, senior Jose Lorenzo Santos continues to prove why he was the 2024 NCAA Division III Statistical Champion, finishing last season with 254 digs and 3.85 digs per set. He’s already off to a strong start with 60 digs in the early games.</span></p>\n<p><span style=\"font-weight: 400;\">Though the season hasn’t started as planned, the Panthers have plenty of time to turn things around. With promising individual performances and lessons learned from close losses, the team will look to improve as the season progresses. </span></p>\n', NULL, 'APPROVED', 'JV375', NULL, '2025-03-27 12:20:27', 0, 'The SUNY Old Westbury Men’s Volleyball team was off to a rough start this season, dropping their first five games and sitting at 0-5 as of March 3rd. Despite their struggles, standout performances from key players suggest that brighter days may be ahead. The Panthers began their season with a scrimmage against Nassau Community College,…\n', NULL, NULL, 3),
('ed20b4a7-61ed-11f1-98fa-60cf847a2597', 'article', 'OW Athletics Hosts Inspiring Women in Sports Panel', 'ow-athletics-hosts-inspiring-women-in-sports-panel', NULL, '<p><span style=\"font-weight: 400;\">In celebration of National Girls and Women in Sports Month, Old Westbury Athletics hosted a panel on Tuesday, February 25th, during common hour in the Panther’s Pad. The event was both powerful and insightful, highlighting women from various sectors of the sports industry. The panel was a unique opportunity for students and attendees to engage in meaningful conversations with professionals who have made significant contributions to athletics. </span></p>\n<p><span style=\"font-weight: 400;\">The panel brought together influential women from diverse backgrounds, each offering a wealth of experience and personal insights. They shared their journeys, discussed the challenges they’ve faced, and highlighted the lessons they&#8217;ve learned along the way, inspiring those in attendance to pursue their own careers in sports.</span></p>\n<p><span style=\"font-weight: 400;\">Gail Wasmus, a former coach at Division II New York Institute of Technology (NYIT), kicked off the panel by providing a deep dive into her decades-long coaching career. Wasmus spoke about how coaching methods have evolved over time and reflected on how the relationship between coaches and players has transformed across generations. She emphasized the importance of adapting coaching styles to meet the needs of today’s athletes, and how creating positive relationships with players can enhance their growth and performance both on and off the field.</span></p>\n<p><span style=\"font-weight: 400;\">Melissa Reilly, the commissioner of the Skyline Conference, passionately discussed her career in sports administration and her path to leadership. As one of the few women in such a prominent role in collegiate athletics, Reilly shared how her experiences as a collegiate athlete prepared her for the challenges of managing a conference. Reilly also encouraged the attendees to consider leadership roles in sports, reinforcing the message that women have the power to shape the future of athletics.</span></p>\n<p><span style=\"font-weight: 400;\">Ali Castellano, one of Old Westbury&#8217;s very own athletic trainers, shared her insights into the critical role athletic trainers play behind the scenes in ensuring athletes’ health and performance. Castellano discussed her passion for injury prevention, rehabilitation, and empowering athletes to reach their full potential. She spoke about the growing recognition of athletic trainers as essential members of athletic teams and how her career in sports medicine allows her to make a direct impact on athletes’ success by keeping them healthy and competitive.</span></p>\n<p><span style=\"font-weight: 400;\">Jerilyn Marinan, a former Division I soccer athlete and current assistant soccer coach at Old Westbury, offered her perspective on the commitment and discipline required to succeed in sports. She highlighted the unique challenges faced by women in sports and how resilience and adaptability have shaped her career. As a coach, Marinan is passionate about helping female athletes develop both their skills and their confidence, stressing the importance of building mental toughness to succeed in athletics and life.</span></p>\n<p><span style=\"font-weight: 400;\">The panel provided an invaluable opportunity for students, faculty, and community members to hear firsthand from these trailblazing women, each of whom has navigated a different path in the sports industry. Whether aspiring to be a coach, administrator, athletic trainer, or player, attendees gained valuable insights into the many opportunities available in sports and how to navigate the challenges of a career in athletics.</span></p>\n<p><span style=\"font-weight: 400;\">Each speaker’s personal story demonstrated the significant progress women have made in athletics and the ongoing efforts needed to break barriers and expand opportunities. The event also highlighted the importance of empowering future generations of female athletes and professionals to take on leadership roles in sports. The inspiring discussions were a testament to the growth and empowerment of women in sports, leaving attendees motivated and equipped with the tools to succeed in their own careers. </span></p>\n', NULL, 'APPROVED', 'JV375', NULL, '2025-03-29 12:37:58', 0, 'In celebration of National Girls and Women in Sports Month, Old Westbury Athletics hosted a panel on Tuesday, February 25th, during common hour in the Panther’s Pad. The event was both powerful and insightful, highlighting women from various sectors of the sports industry. The panel was a unique opportunity for students and attendees to engage…\n', NULL, NULL, 3),
('ed212f7c-61ed-11f1-98fa-60cf847a2597', 'podcast', 'Media News for You!', 'media-news-for-you-2', NULL, '<h2><strong>This Week on New Media Beat:</strong></h2>\n<h2></h2>\n<audio class=\"wp-audio-shortcode\" id=\"audio-11247-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-3-Web-2025-03-27.mp3?_=1\" /><a href=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-3-Web-2025-03-27.mp3\">https://newmediabeat.org/wp-content/uploads/2025/03/NMB-3-Web-2025-03-27.mp3</a></audio>\n<h2></h2>\n<ul>\n<li><strong>Netflix Localizing Production in Mexico!</strong></li>\n<li><strong style=\"letter-spacing: 0em;\"><span class=\"TextRun SCXW162612181 BCX0\" lang=\"EN-US\" xml:lang=\"EN-US\" data-contrast=\"auto\"><span class=\"NormalTextRun SCXW162612181 BCX0\">Can a Branded Podcast Make You Hungry?</span></span></strong></li>\n<li><strong>Make It Fair? U.K. Creatives Take On Big A.I.</strong></li>\n<li><strong>What TikTok Ban?</strong></li>\n<li><strong>Tech Makes Basketball Vibrate!</strong></li>\n<li><strong>Google&#8217;s A.I. Co-Scientist Explained!</strong></li>\n</ul>\n<p><a href=\"https://www.newmediabeat.org/\"><strong>New Media Beat</strong></a> covers new media news from around the world. NMB is a production of <a href=\"https://www.oldwestbury.edu/programs-courses/media-and-communications-ba\">Media &amp; Communications</a> students from <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener\">SUNY Old Westbury.</a>   We scour the web for news about about media and journalism.</p>\n<p>NMB is co-produced by Jaden Nunez, John Deliso, and Henry Wilson. Our engineer this week is Jaden Nunez.  Our hosts are Kate Espinal and Muhamed Doucouré.</p>\n<p>The NMB Podcast streams live on <a href=\"http://www.owwrny.org/\">Old Westbury Web Radio</a> Thursdays from 12:00-1:00 PM EST.  Can&#8217;t listen live? Our podcast will be <a href=\"https://newmediabeat.org/?cat=17\">posted</a> for your listening pleasure every Friday afternoon.</p>\n<p><a href=\"uploads/NMB-3-Hands-Script-NMB-Rect.jpg\"><img loading=\"lazy\" decoding=\"async\" class=\"alignnone size-full wp-image-8553\" src=\"uploads/NMB-3-Hands-Script-NMB-Rect.jpg\" alt=\"\" width=\"2005\" height=\"1046\" /></a></p>\n', NULL, 'APPROVED', 'TC527', NULL, '2025-03-28 23:01:59', 0, 'This Week on New Media Beat: Netflix Localizing Production in Mexico! Can a Branded Podcast Make You Hungry? Make It Fair? U.K. Creatives Take On Big A.I. What TikTok Ban? Tech Makes Basketball Vibrate! Google’s A.I. Co-Scientist Explained! New Media Beat covers new media news from around the world. NMB is a production of Media…\n', NULL, NULL, 1),
('ed2183f5-61ed-11f1-98fa-60cf847a2597', 'podcast', 'Seven Stories from New Media Beat!', 'seven-stories-from-new-media-beat', NULL, '<h2></h2>\n<h2><strong>This Week on New Media Beat:</strong></h2>\n<h2></h2>\n<audio class=\"wp-audio-shortcode\" id=\"audio-11255-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-2-Web-2025-03-13.mp3?_=1\" /><a href=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-2-Web-2025-03-13.mp3\">https://newmediabeat.org/wp-content/uploads/2025/03/NMB-2-Web-2025-03-13.mp3</a></audio>\n<h2></h2>\n<ul>\n<li><strong>Artificial Intelligence in Public Relations!</strong></li>\n<li><strong style=\"letter-spacing: 0em;\"><span class=\"TextRun SCXW162612181 BCX0\" lang=\"EN-US\" xml:lang=\"EN-US\" data-contrast=\"auto\"><span class=\"NormalTextRun SCXW162612181 BCX0\">Can AI Write Scripts?</span></span></strong></li>\n<li><strong>Why Do <a href=\"https://www.ncaa.org/sports/2021/7/9/name-image-likeness.aspx\">NIL</a> Athletes Love TikTok?</strong></li>\n<li><strong>Who Are the Popular Kids in the White House Press Room?</strong></li>\n<li><strong>The Trouble with Deepfakes. . .</strong></li>\n<li><strong>Will AI Make Journalists More Creative?</strong></li>\n<li><strong>Can You Keep Up with the Algorithms?</strong></li>\n</ul>\n<p>Listen to the <a href=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-2-Web-2025-03-13.mp3\">second podcast</a> of the spring season!</p>\n<p><a href=\"https://www.newmediabeat.org/\"><strong>New Media Beat</strong></a> covers new media news from around the world. NMB is a production of Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener\">SUNY College @ Old Westbury.</a>   We scour the web for news about about media and journalism.</p>\n<p>NMB is co-produced by Jaden Nunez, John Deliso, Quinn Dobson, and Henry Wilson. Our engineer this week is Quinn Dobson.  Our hosts are Donovan Johnson and Juliana Vasquez.</p>\n<p>The NMB Podcast streams live on <a href=\"http://www.owwrny.org/\">Old Westbury Web Radio</a> Thursdays from 12:00-1:00 PM EST.  Can&#8217;t listen live? Our podcast will be <a href=\"https://newmediabeat.org/?cat=17\">posted</a> for your listening pleasure every Friday afternoon.</p>\n<p><a href=\"uploads/NMB-2-Scripts-Hand-NMB-Red-Rect.jpg\"><img loading=\"lazy\" decoding=\"async\" class=\"alignnone size-full wp-image-8500\" src=\"uploads/NMB-2-Scripts-Hand-NMB-Red-Rect.jpg\" alt=\"\" width=\"1387\" height=\"536\" /></a></p>\n', NULL, 'APPROVED', 'TC527', NULL, '2025-03-14 17:37:03', 0, 'This Week on New Media Beat: Artificial Intelligence in Public Relations! Can AI Write Scripts? Why Do NIL Athletes Love TikTok? Who Are the Popular Kids in the White House Press Room? The Trouble with Deepfakes. . . Will AI Make Journalists More Creative? Can You Keep Up with the Algorithms? Listen to the second…\n', NULL, NULL, 1),
('ed21ddcf-61ed-11f1-98fa-60cf847a2597', 'podcast', 'Brand New Media Beat!', 'brand-new-media-beat', NULL, '<h2></h2>\n<h2><strong>This Week on New Media Beat:</strong></h2>\n<h2></h2>\n<audio class=\"wp-audio-shortcode\" id=\"audio-11260-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-1-Web-2025-02-27.mp3?_=1\" /><a href=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-1-Web-2025-02-27.mp3\">https://newmediabeat.org/wp-content/uploads/2025/03/NMB-1-Web-2025-02-27.mp3</a></audio>\n<h2></h2>\n<ul>\n<li><strong>What Is BuzzFeed Island? </strong></li>\n<li><strong style=\"letter-spacing: 0em;\"><span class=\"TextRun SCXW162612181 BCX0\" lang=\"EN-US\" xml:lang=\"EN-US\" data-contrast=\"auto\"><span class=\"NormalTextRun SCXW162612181 BCX0\">Is AI Replacing Human Ingenuity in Fashion?</span></span></strong></li>\n<li><strong>Are Basketball Fans Ready for Virtual Worlds?</strong></li>\n<li><strong>Social AI: Better Conversations or More Discord?</strong></li>\n<li><strong>How Did Scammers Use AI to Steal Sandra Bullock&#8217;s Identity?</strong></li>\n</ul>\n<p>Welcome to the new spring season of <em>New Media Beat!</em></p>\n<p><a href=\"https://www.newmediabeat.org/\"><strong>New Media Beat</strong></a> covers new media news from around the world. NMB is a production of Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener\">SUNY College @ Old Westbury.</a>   We scour the web for news about about media and journalism.</p>\n<p>NMB is produced by Jaden Nunez and John Deliso. Our engineer this week is Jaden Nunez. Our hosts are Samantha Stock and John Deliso.  This week we have two new production team members joining us: Quinn Dobson and Henry Wilson</p>\n<p>The NMB Podcast streams live on <a href=\"http://www.owwrny.org/\">Old Westbury Web Radio</a> Thursdays from 12:00-1:00 PM EST.  Can&#8217;t listen live? Our podcast will be <a href=\"https://newmediabeat.org/?cat=17\">posted</a> for your listening pleasure every Friday afternoon.</p>\n<p><a href=\"uploads/NMB-1-Ice-Banner-Blank-scaled.jpg\"><img loading=\"lazy\" decoding=\"async\" class=\"aligncenter wp-image-8393 size-full\" src=\"uploads/NMB-1-Ice-Banner-Blank-scaled.jpg\" alt=\"\" width=\"2560\" height=\"925\" /></a></p>\n', NULL, 'APPROVED', 'TC527', NULL, '2025-03-04 17:47:50', 0, 'This Week on New Media Beat: What Is BuzzFeed Island? Is AI Replacing Human Ingenuity in Fashion? Are Basketball Fans Ready for Virtual Worlds? Social AI: Better Conversations or More Discord? How Did Scammers Use AI to Steal Sandra Bullock’s Identity? Welcome to the new spring season of New Media Beat! New Media Beat covers new…\n', NULL, NULL, 1),
('ed2232eb-61ed-11f1-98fa-60cf847a2597', 'article', 'Amadi Lee-Kane: A Player Profile', 'amadi-lee-kane-a-player-profile', NULL, '<p><span style=\"font-weight: 400;\">Amadi Lee-Kane is a 6-foot-1 senior combo guard from Washington, D.C., who has been turning heads on the basketball court with his impressive stats and unwavering dedication to his game. Known for his scoring ability, playmaking skills, and leadership on and off the court, Lee-Kane is a key player for his team. This past season, he averaged 16.8 points per game, 5.8 rebounds per  game, 2.6 assists, and 1.75 steals. Last season, Lee-Kane averaged 17.5 points per game, 5.5  rebounds per game, and 2 assists, while maintaining remarkable shooting percentages—over  46% from the field, over 35% from beyond the arc, and above 80% from the free-throw line. His  consistency and efficiency have made him one of the standout players in his league. </span></p>\n<p><span style=\"font-weight: 400;\">Amadi’s love for basketball runs deep, beginning at a very young age. He started playing the  game at just two years old when his dad gave him a basketball while he was still in the cradle. Growing up in a family that loved basketball, it was no surprise that he was instantly drawn to the sport. By the time he was five, Amadi started taking the game seriously, working on his fundamentals and training to improve his skills.</span></p>\n<p><span style=\"font-weight: 400;\">Every offseason, Amadi takes a strategic approach to his training, changing things up depending  on what he feels he needs to improve. Last year, he decided to go back home and play in  professional runs, gaining valuable experience by playing for multiple teams. This experience allowed him to understand the business side of basketball and how important the environment  can be in shaping a player&#8217;s career. Amadi values mental strength and sees it as a key aspect of  his game. While he does conditioning and works on his physical abilities, he spends a lot of time focusing on mental exercises to maintain his mental sharpness and reach his highest potential.  His goal is to “find his flow state” and always play at his best. </span></p>\n<p><span style=\"font-weight: 400;\">Amadi’s leadership goes beyond his performance on the court. He has always been surrounded  by people who uplift him in his lowest moments, and he carries that same energy to support his  teammates. Whether it’s giving constructive criticism or simply being there as a friend, Amadi is committed to building strong relationships with his teammates and ensuring that they feel  supported both on and off the court. As I have gotten to know him personally, he is always there to offer a hand or an ear, whether it’s in person or over the phone, maintaining a strong sense of brotherhood within the team. </span></p>\n<p><span style=\"font-weight: 400;\">Amadi has had several moments where he truly made an impact, one of which came in a game winning situation against SUNY Purchase. During that game, he set a crucial screen</span></p>\n<p><span style=\"font-weight: 400;\">for Zion Williams, got the ball back, and made the game-winning layup to seal the victory. Another memorable play came last year against USMMA when Amadi hit a step back three-pointer to tie the game, even though his team eventually lost. That shot gave him hope and showed him that, even in tough moments,  he and his team could compete against great opponents. </span></p>\n<p><span style=\"font-weight: 400;\">As Amadi enters his final year of college basketball, he’s focused on finding the best situation  for his future, both academically and on the court. He recently entered the transfer portal to explore his options and ensure that his next move aligns with his goals. Amadi’s end goal is to continue playing basketball at the highest level, and he has his sights set on playing overseas. He’s excited to see the world, continue growing his game, and compete at the highest level possible. However, he’s also taking his time with his decision, understanding that patience is key. “I’d rather move slow than not move at all,” he says, adding that he’s trusting God to guide  his next steps in this journey. </span></p>\n<p><span style=\"font-weight: 400;\">Amadi Lee-Kane’s combination of skill, leadership, and determination makes him a player to watch as he continues to pursue his dreams on the court. Whether it&#8217;s improving his game, supporting his teammates, or looking ahead to his next move, Amadi remains focused on his  journey and ready for the next chapter in his basketball career.</span></p>\n', NULL, 'APPROVED', 'AP963', NULL, '2025-03-30 19:44:14', 0, 'Amadi Lee-Kane is a 6-foot-1 senior combo guard from Washington, D.C., who has been turning heads on the basketball court with his impressive stats and unwavering dedication to his game. Known for his scoring ability, playmaking skills, and leadership on and off the court, Lee-Kane is a key player for his team. This past season,…\n', NULL, NULL, 7),
('ed22a3b4-61ed-11f1-98fa-60cf847a2597', 'article', 'Panthers Fight Back to Claim Conference Win Over The Marines', 'panthers-fight-back-to-claim-conference-win-over-the-marines', NULL, '<p><span style=\"font-weight: 400;\">The Old Westbury Panthers won a close game against the United States Merchant Marine Academy Marines in Kings Point on February 11th, 69-65, after a strong second-half comeback. This victory broke their two-game losing streak and gave them momentum for the rest of their conference games.</span></p>\n<p><span style=\"font-weight: 400;\">The Panthers struggled early, falling behind 0-7, but they fought back. Kellen Leake hit a three-pointer and Zion Williams made a mid-range jumper, getting the Panthers within two points. They kept closing the gap and tied the game at 18-18 after back-to-back strong drives by Amadi Lee Kane.</span></p>\n<p><span style=\"font-weight: 400;\">The first half was full of lead changes. Although the Panthers had some turnover issues, Jamari Williams scored consecutive baskets to briefly give them the lead. The Marines hit several three-pointers, including a big &#8220;and-one&#8221; play, ending the half with a 39-28 lead. Zion Williams led the Panthers with 11 points at the break, while the Marines’ Castle scored 15 points.</span></p>\n<p><span style=\"font-weight: 400;\">The Panthers came out strong after halftime. Amadi Lee Kane’s free throws started the comeback, and the Panthers tied the game 46-46. Zion Williams gave Old Westbury their first lead of the second half with a strong drive to the basket. The game remained close, with the score switching back and forth. In the final minutes, Kellen Leake hit a clutch three-pointer, and Zion Williams nailed a contested step-back three to give the Panthers a 64-62 lead with 1:30 left to go.</span></p>\n<p><span style=\"font-weight: 400;\">In the last 39 seconds, the Panthers led 68-65. Amadi Lee Kane made the first free throw and missed the second, but Joel Ofori grabbed a crucial offensive rebound to secure the win.</span></p>\n<p><span style=\"font-weight: 400;\">Zion Williams led the Panthers with 21 points, 8 rebounds, and 5 assists. Amadi Lee Kane finished with 19 points and 7 rebounds, and Kellen Leake added 13 points. For the Marines, Zalescik had a double-double with 21 points and 10 rebounds.</span></p>\n<p><span style=\"font-weight: 400;\">Looking ahead, the Panthers will need to keep this momentum as they try to make a playoff run, with their game against St. Joseph&#8217;s University Brooklyn on February 15th. </span></p>\n<p>&nbsp;</p>\n', NULL, 'APPROVED', 'AP963', NULL, '2025-03-30 19:48:22', 0, 'The Old Westbury Panthers won a close game against the United States Merchant Marine Academy Marines in Kings Point on February 11th, 69-65, after a strong second-half comeback. This victory broke their two-game losing streak and gave them momentum for the rest of their conference games. The Panthers struggled early, falling behind 0-7, but they…\n', NULL, NULL, 7),
('ed22f349-61ed-11f1-98fa-60cf847a2597', 'video', 'More Media News!', 'more-media-news', NULL, '<h2><strong>This Week on New Media Beat:</strong></h2>\n<h2></h2>\n<audio class=\"wp-audio-shortcode\" id=\"audio-11282-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"https://newmediabeat.org/wp-content/uploads/2025/04/NMB-4-Web-2025-04-03.mp3?_=1\" /><a href=\"https://newmediabeat.org/wp-content/uploads/2025/04/NMB-4-Web-2025-04-03.mp3\">https://newmediabeat.org/wp-content/uploads/2025/04/NMB-4-Web-2025-04-03.mp3</a></audio>\n<h2></h2>\n<ul>\n<li><strong>Child Content Creator Compensation!</strong></li>\n<li><strong>Should Fizz Be the Big App on Campus?</strong></li>\n<li><strong>Could Instagram Reels Fill a TikTok Hole?</strong></li>\n<li><strong>Influencers vs. Journalists: Who Can You Trust?</strong></li>\n<li><strong>Ghost Voices: Should A.I. Resurrect the Dead?</strong></li>\n<li><strong>Political Deepfakes 2024: Electoral Pests?</strong></li>\n</ul>\n<p>Listen to the <a href=\"https://newmediabeat.org/wp-content/uploads/2025/03/NMB-2-Web-2025-03-13.mp3\">second podcast</a> of the spring season!</p>\n<p><a href=\"https://www.newmediabeat.org/\"><strong>New Media Beat</strong></a> covers new media news from around the world. NMB is a production of Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener\">SUNY College @ Old Westbury.</a>   We scour the web for news about about media and journalism.</p>\n<p>NMB is co-produced by Jaden Nunez, John Deliso, Quinn Dobson, and Henry Wilson. Our engineer this week is Quinn Dobson.  Our hosts are Donovan Johnson and Juliana Vasquez.</p>\n<p>The NMB Podcast streams live on <a href=\"http://www.owwrny.org/\">Old Westbury Web Radio</a> Thursdays from 12:00-1:00 PM EST.  Can&#8217;t listen live? Our podcast will be <a href=\"https://newmediabeat.org/?cat=17\">posted</a> for your listening pleasure every Friday afternoon.</p>\n<p>