('ed4a9b7a-61ed-11f1-98fa-60cf847a2597', 'video', 'OWTV News October Episode', 'owtv-news-october-episode', NULL, '<p>OWTV News Team covers stories from president Dr. Butts&#8217;s retirement to the new Virtual Reality Lab at Old Westbury.</p>\n<p><iframe loading=\"lazy\" src=\"https://www.youtube.com/embed/SpGmfblFFFA\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"allowfullscreen\"></iframe></p>\n', NULL, 'APPROVED', 'TC527', NULL, '2019-11-11 10:58:05', 0, 'OWTV News Team covers stories from president Dr. Butts’s retirement to the new Virtual Reality Lab at Old Westbury.\n', NULL, NULL, 1),
