('ed4b9a49-61ed-11f1-98fa-60cf847a2597', 'video', 'We Got Your Global Media News Right Here!', 'we-got-your-global-media-news-right-here', NULL, '<p><a href=\"uploads/GMN-11-Image-2-20191205.png\"><img loading=\"lazy\" decoding=\"async\" src=\"uploads/GMN-11-Image-2-20191205.png\" alt=\"\" width=\"640\" height=\"481\" class=\"alignnone size-full wp-image-4536\" srcset=\"https://oldwestburycatalyst.org/wp-content/uploads/2019/12/GMN-11-Image-2-20191205.png 640w, https://oldwestburycatalyst.org/wp-content/uploads/2019/12/GMN-11-Image-2-20191205-600x451.png 600w, https://oldwestburycatalyst.org/wp-content/uploads/2019/12/GMN-11-Image-2-20191205-300x225.png 300w\" sizes=\"auto, (max-width: 640px) 100vw, 640px\" /></a><br />\n<audio class=\"wp-audio-shortcode\" id=\"audio-4533-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-11-Web-20191205.mp3?_=1\" /><a href=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-11-Web-20191205.mp3\">http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-11-Web-20191205.mp3</a></audio></p>\n<p><strong>Media News from Russia, Pakistan, China, Bolivia, Canada, South Korea:</strong></p>\n<ul>\n<li>How Close to the Kremlin is the Chef&#8217;s Patriot Media Group?</li>\n<li>Can Imran Khan Regulate the Pakistani Press?</li>\n<li>Have You Met Bytedance? Is TikTok a Privacy Threat?</li>\n<li>Why Has China Slammed the Door on The Joker?</li>\n<li>Will Boliva&#8217;s New President Jeanine Áñez Rein in the Media Before the Next Election?</li>\n<li>Can Social Media Protests Stop a Tuition Hike in Canada?</li>\n<li>From K-Pop to Parasite: South Korea&#8217;s Media Exports Are Big Business.</li>\n</ul>\n<p><strong><a href=\"https://wcownews.typepad.com/globalmedia/\" rel=\"noopener noreferrer\" target=\"_blank\">Global Media News</a> </strong>is a weekly webcast covering media news from around the world.&nbsp; GMN is a production of&nbsp; Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener noreferrer\">SUNY College @ Old Westbury.</a>&nbsp;&nbsp; We scour the web for news about about the world of media, journalism and technology.</p>\n<p>Listen to our next&nbsp; podcast streaming live on <strong><a href=\"http://www.owwr.org/\" rel=\"noopener noreferrer\" target=\"_blank\">OWWR</a></strong>: Thursday December 12, 2019 @ 10 am EST.</p>\n<p>Can&#8217;t listen live? Our next podcast &nbsp;will be posted by 3:00pm, December 12, 2019.</p>\n<p><strong><a href=\"https://feeds.feedburner.com/GlobalMediaNews\" target=\"_self\" rel=\"noopener noreferrer\">Subscribe Now!</a></strong></p>\n<p>Follow<strong> <a href=\"https://twitter.com/OWWRGMN\" rel=\"noopener noreferrer\" target=\"_blank\">@OWWRGMN</a></strong> for a curated feed of the latest new media news for aspiring media professionals.</p>\n', NULL, 'APPROVED', 'TC527', NULL, '2019-12-05 12:44:57', 0, 'Media News from Russia, Pakistan, China, Bolivia, Canada, South Korea: How Close to the Kremlin is the Chef’s Patriot Media Group? Can Imran Khan Regulate the Pakistani Press? Have You Met Bytedance? Is TikTok a Privacy Threat? Why Has China Slammed the Door on The Joker? Will Boliva’s New President Jeanine Áñez Rein in the…\n', NULL, NULL, 15),
('ed4be686-61ed-11f1-98fa-60cf847a2597', 'video', 'Podcast: Global Media News!', '4541', NULL, '<figure id=\"attachment_4543\" aria-describedby=\"caption-attachment-4543\" style=\"width: 512px\" class=\"wp-caption alignnone\"><a href=\"uploads/GMN-12-Tree-GIF-3.gif\"><img loading=\"lazy\" decoding=\"async\" class=\"size-full wp-image-4543\" src=\"uploads/GMN-12-Tree-GIF-3.gif\" alt=\"\" width=\"512\" height=\"512\" /></a><figcaption id=\"caption-attachment-4543\" class=\"wp-caption-text\">Listen to Our Podcast!</figcaption></figure>\n<p><strong>Media News from Turkey, Afghanistan, Yemen, Malaysia, Japan, Iraq, Sudan:</strong></p>\n<audio class=\"wp-audio-shortcode\" id=\"audio-4541-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-12-Web-20191212.mp3?_=1\" /><a href=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-12-Web-20191212.mp3\">http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-12-Web-20191212.mp3</a></audio>\n<p>&nbsp;</p>\n<ul>\n<li>Is There Press Freedom in Erdoğan&#8217;s Turkey?</li>\n<li>ZAN TV: Gender &amp; Journalism in Afghanistan.</li>\n<li>Yemen: Can You Report from a Bloody Civil War?</li>\n<li>Malaysian Media Under Mahathir bin Mohamad.</li>\n<li>Is Twitter a Thing in Japan? Why so Popular?</li>\n<li>Iraqi Protesters Using Whatsapp to Fight the Power.</li>\n<li>After Al-Bashir: Is There Internet Freedom in Sudan?</li>\n</ul>\n<p><strong><a href=\"https://wcownews.typepad.com/globalmedia/\" target=\"_blank\" rel=\"noopener noreferrer\">Global Media News</a> </strong>is a weekly webcast covering media news from around the world.  GMN is a production of  Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener noreferrer\">SUNY College @ Old Westbury.</a>   We scour the web for news about about the world of media, journalism and technology.</p>\n<p>That&#8217;s all for this season: Look for us in February, 2020.</p>\n<p>Listen to our next  podcast streaming live on <strong><a href=\"http://www.owwr.org/\" target=\"_blank\" rel=\"noopener noreferrer\">OWWR</a></strong>: Thursday February 6, 2020 @ 10 am EST.</p>\n<p>Can&#8217;t listen live? Our next podcast  will be posted by 3:00pm, Thursday February 6, 2020.</p>\n<p><strong><a href=\"https://feeds.feedburner.com/GlobalMediaNews\" target=\"_self\" rel=\"noopener noreferrer\">Subscribe Now!</a></strong></p>\n<p>Follow<strong> <a href=\"https://twitter.com/OWWRGMN\" target=\"_blank\" rel=\"noopener noreferrer\">@OWWRGMN</a></strong> for a curated feed of the latest new media news for aspiring media professionals.</p>\n', NULL, 'APPROVED', 'TC527', NULL, '2019-12-12 13:19:10', 0, 'Media News from Turkey, Afghanistan, Yemen, Malaysia, Japan, Iraq, Sudan:   Is There Press Freedom in Erdoğan’s Turkey? ZAN TV: Gender & Journalism in Afghanistan. Yemen: Can You Report from a Bloody Civil War? Malaysian Media Under Mahathir bin Mohamad. Is Twitter a Thing in Japan? Why so Popular? Iraqi Protesters Using Whatsapp to Fight…\n', NULL, NULL, 15),
('ed4c3147-61ed-11f1-98fa-60cf847a2597', 'video', 'Podcast: Your New Media News Update!', 'podcast-your-new-media-news-update', NULL, '<figure id=\"attachment_4562\" aria-describedby=\"caption-attachment-4562\" style=\"width: 320px\" class=\"wp-caption alignnone\"><img loading=\"lazy\" decoding=\"async\" class=\"size-full wp-image-4562\" src=\"uploads/GMN-Square-.png\" alt=\"Global Media News!\" width=\"320\" height=\"320\" srcset=\"https://oldwestburycatalyst.org/wp-content/uploads/2020/02/GMN-Square-.png 320w, https://oldwestburycatalyst.org/wp-content/uploads/2020/02/GMN-Square--70x70.png 70w, https://oldwestburycatalyst.org/wp-content/uploads/2020/02/GMN-Square--300x300.png 300w\" sizes=\"auto, (max-width: 320px) 100vw, 320px\" /><figcaption id=\"caption-attachment-4562\" class=\"wp-caption-text\">It&#8217;s Podcast Time: Get your new media news while it&#8217;s hot!</figcaption></figure>\n<audio class=\"wp-audio-shortcode\" id=\"audio-4561-1\" preload=\"none\" style=\"width: 100%;\" controls=\"controls\"><source type=\"audio/mpeg\" src=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-1-Web-2020-02-06.mp3?_=1\" /><a href=\"http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-1-Web-2020-02-06.mp3\">http://www.oldwestburycatalyst.org/wp-content/uploads/GMN-1-Web-2020-02-06.mp3</a></audio>\n<p><strong>This Week in New Media News :</strong></p>\n<ul>\n<li>Can the Federal Trade Commission Regulate Content on Youtube?</li>\n<li>Spotify vs. Apple Music: Who Will End Up with All the Users?</li>\n<li>No Negative News: Why Is China Arresting WeChat Users?</li>\n<li>Are Snapchat&#8217;s Fans in Law Enforcement Following You?</li>\n<li>Will Facebook Limit Political Misinformation?</li>\n<li>What Does Zuck Have to Say About Freedom of Expression?</li>\n<li>TikTok for Marketers: What&#8217;s Not to Love?</li>\n<li>How Big a Deal Is 5G for the Future of Journalism?</li>\n</ul>\n<p><strong><a href=\"https://wcownews.typepad.com/globalmedia/\" target=\"_blank\" rel=\"noopener noreferrer\">Global Media News</a> </strong>is a weekly webcast covering new media news from around the world.  GMN is a production of  Media Studies students from the <a href=\"https://www.oldwestbury.edu/\" target=\"_self\" rel=\"noopener noreferrer\">SUNY College @ Old Westbury.</a>   We scour the web for news about about the world of media, journalism and technology.</p>\n<p>Listen to our next  podcast streaming live on <strong><a href=\"http://www.owwr.org/\" target=\"_blank\" rel=\"noopener noreferrer\">OWWR</a></strong>: Thursday February 13, 2020 @ 10 am EST.</p>\n<p>Can&#8217;t listen live? Our next podcast  will be posted by 3:00pm, Thursday February 13, 2020.</p>\n<p><strong><a href=\"https://feeds.feedburner.com/GlobalMediaNews\" target=\"_self\" rel=\"noopener noreferrer\">Subscribe Now!</a></strong></p>\n<p>Follow<strong> <a href=\"https://twitter.com/OWWRGMN\" target=\"_blank\" rel=\"noopener noreferrer\">@OWWRGMN</a></strong> for a curated feed of the latest new media news for aspiring media professionals.</p>\n', NULL, 'APPROVED', 'TC527', NULL, '2020-02-06 14:12:08', 0, 'This Week in New Media News : Can the Federal Trade Commission Regulate Content on Youtube? Spotify vs. Apple Music: Who Will End Up with All the Users? No Negative News: Why Is China Arresting WeChat Users? Are Snapchat’s Fans in Law Enforcement Following You? Will Facebook Limit Political Misinformation? What Does Zuck Have to…\n', NULL, NULL, 15),
